Create robust file watching infrastructure for hot-reload configuration using the notify crate.

## Implementation
```rust
// src/watch_config.rs
use notify::{
    Config, Event, EventKind, RecommendedWatcher, RecursiveMode, Watcher,
    event::{ModifyKind, DataChange},
};
use std::path::{Path, PathBuf};
use std::sync::mpsc::{channel, Receiver};
use std::time::{Duration, Instant};
use tracing::{debug, trace, info, warn, error, instrument, span, Level};

/// File watcher for configuration hot-reload
pub struct ConfigWatcher {
    watcher: RecommendedWatcher,
    receiver: Receiver<Result<Event, notify::Error>>,
    config_path: PathBuf,
    debounce_duration: Duration,
    last_event_time: Option<Instant>,
}

impl ConfigWatcher {
    /// Create a new config watcher for the given path
    #[instrument(skip_all, fields(path = %config_path.display()))]
    pub fn new(config_path: PathBuf, debounce_ms: u64) -> Result<Self, WatchError> {
        // Verify file exists and is readable
        if !config_path.exists() {
            return Err(WatchError::FileNotFound(config_path.clone()));
        }

        if !config_path.is_file() {
            return Err(WatchError::NotAFile(config_path.clone()));
        }

        let (tx, rx) = channel();

        // Create watcher with recommended settings
        let watcher = RecommendedWatcher::new(
            move |res: Result<Event, notify::Error>| {
                let _ = tx.send(res);
            },
            Config::default()
                .with_poll_interval(Duration::from_millis(500))
                .with_compare_contents(true),  // Detect content changes, not just metadata
        )?;

        info!("Config watcher initialized");

        Ok(Self {
            watcher,
            receiver: rx,
            config_path,
            debounce_duration: Duration::from_millis(debounce_ms),
            last_event_time: None,
        })
    }

    /// Start watching the config file
    #[instrument(skip(self))]
    pub fn start_watching(&mut self) -> Result<(), WatchError> {
        // Watch the parent directory to handle editors that use atomic saves
        // (write to temp, rename to target)
        let parent = self.config_path.parent()
            .ok_or_else(|| WatchError::NoParentDir(self.config_path.clone()))?;

        trace!(dir = %parent.display(), "Watching parent directory");
        self.watcher.watch(parent, RecursiveMode::NonRecursive)?;

        info!(path = %self.config_path.display(), "Started watching config file");
        Ok(())
    }

    /// Stop watching
    pub fn stop_watching(&mut self) -> Result<(), WatchError> {
        if let Some(parent) = self.config_path.parent() {
            self.watcher.unwatch(parent)?;
        }
        info!("Stopped watching config file");
        Ok(())
    }

    /// Poll for file changes with timeout
    /// Returns Some(()) if config file changed, None if timeout
    #[instrument(skip(self), level = "trace")]
    pub fn poll_change(&mut self, timeout: Duration) -> Result<Option<()>, WatchError> {
        match self.receiver.recv_timeout(timeout) {
            Ok(Ok(event)) => {
                if self.is_relevant_event(&event) {
                    // Debounce: ignore events too close together
                    if let Some(last_time) = self.last_event_time {
                        if last_time.elapsed() < self.debounce_duration {
                            trace!(
                                elapsed_ms = %last_time.elapsed().as_millis(),
                                debounce_ms = %self.debounce_duration.as_millis(),
                                "Event within debounce window, skipping"
                            );
                            return Ok(None);
                        }
                    }

                    self.last_event_time = Some(Instant::now());
                    debug!(kind = ?event.kind, "Config file changed");
                    Ok(Some(()))
                } else {
                    trace!(kind = ?event.kind, "Ignoring irrelevant event");
                    Ok(None)
                }
            }
            Ok(Err(e)) => {
                warn!(error = %e, "Watch error");
                Err(WatchError::Notify(e))
            }
            Err(std::sync::mpsc::RecvTimeoutError::Timeout) => {
                Ok(None)
            }
            Err(std::sync::mpsc::RecvTimeoutError::Disconnected) => {
                error!("Watch channel disconnected");
                Err(WatchError::ChannelDisconnected)
            }
        }
    }

    /// Check if this event is relevant to our config file
    fn is_relevant_event(&self, event: &Event) -> bool {
        // Must involve our config file
        let involves_config = event.paths.iter().any(|p| {
            p == &self.config_path || 
            p.file_name() == self.config_path.file_name()
        });

        if !involves_config {
            return false;
        }

        // Must be a modify or create event (handles atomic saves)
        matches!(
            event.kind,
            EventKind::Modify(ModifyKind::Data(_)) |
            EventKind::Modify(ModifyKind::Any) |
            EventKind::Create(_)
        )
    }

    /// Get the path being watched
    pub fn config_path(&self) -> &Path {
        &self.config_path
    }
}

#[derive(Debug, thiserror::Error)]
pub enum WatchError {
    #[error("Config file not found: {0}")]
    FileNotFound(PathBuf),

    #[error("Path is not a file: {0}")]
    NotAFile(PathBuf),

    #[error("Cannot determine parent directory: {0}")]
    NoParentDir(PathBuf),

    #[error("Notify error: {0}")]
    Notify(#[from] notify::Error),

    #[error("Watch channel disconnected")]
    ChannelDisconnected,
}

/// Watch loop that applies config on changes
#[instrument(skip_all, fields(config = %config_path.display()))]
pub fn run_watch_loop<F>(
    config_path: PathBuf,
    debounce_ms: u64,
    mut apply_fn: F,
) -> Result<(), WatchError>
where
    F: FnMut(&Path) -> Result<usize, Box<dyn std::error::Error>>,
{
    let mut watcher = ConfigWatcher::new(config_path.clone(), debounce_ms)?;
    watcher.start_watching()?;

    // Initial apply
    info!("Applying initial configuration");
    match apply_fn(&config_path) {
        Ok(changes) => info!(changes = %changes, "Initial configuration applied"),
        Err(e) => error!(error = %e, "Failed to apply initial configuration"),
    }

    println!("Watching {} for changes (Ctrl+C to stop)...", config_path.display());

    loop {
        match watcher.poll_change(Duration::from_millis(100)) {
            Ok(Some(())) => {
                info!("Change detected, reloading");
                match apply_fn(&config_path) {
                    Ok(changes) => {
                        info!(changes = %changes, "Configuration reloaded");
                        println!("[{}] Applied {} changes", 
                            chrono::Local::now().format("%H:%M:%S"),
                            changes);
                    }
                    Err(e) => {
                        error!(error = %e, "Failed to apply configuration");
                        eprintln!("[{}] Error: {}", 
                            chrono::Local::now().format("%H:%M:%S"),
                            e);
                    }
                }
            }
            Ok(None) => {
                // Timeout, continue loop
            }
            Err(WatchError::ChannelDisconnected) => {
                info!("Watcher shutting down");
                break;
            }
            Err(e) => {
                error!(error = %e, "Watch error");
            }
        }
    }

    watcher.stop_watching()?;
    Ok(())
}
```

## Editor Compatibility Notes
Different editors save files differently:
- **vim/neovim**: Writes to temp file, then renames (atomic)
- **VSCode**: Direct write to file
- **Sublime Text**: Creates backup, writes, deletes backup
- **IntelliJ**: Uses safe write with temp file

By watching the parent directory and handling both Modify and Create events, we handle all these cases.

## Unit Tests
```rust
#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    #[test]
    fn test_watcher_creation() {
        let temp = TempDir::new().unwrap();
        let config = temp.path().join("config.yaml");
        std::fs::write(&config, "test: true").unwrap();

        let watcher = ConfigWatcher::new(config, 100);
        assert!(watcher.is_ok());
    }

    #[test]
    fn test_watcher_file_not_found() {
        let result = ConfigWatcher::new(PathBuf::from("/nonexistent/config.yaml"), 100);
        assert!(matches!(result, Err(WatchError::FileNotFound(_))));
    }

    #[test]
    fn test_debounce() {
        let temp = TempDir::new().unwrap();
        let config = temp.path().join("config.yaml");
        std::fs::write(&config, "test: true").unwrap();

        let mut watcher = ConfigWatcher::new(config.clone(), 500).unwrap();
        watcher.start_watching().unwrap();

        // Rapid modifications should be debounced
        for _ in 0..5 {
            std::fs::write(&config, "test: modified").unwrap();
            std::thread::sleep(Duration::from_millis(50));
        }

        // Should only register one change due to debouncing
        // (Test timing is tricky, this is more of a smoke test)
    }
}
