    // Parse based on format
    let config: ProfileConfig = match format {
        ConfigFormat::Yaml => {
            serde_yaml::from_str(&content)
                .map_err(|e| ConfigError::ParseError(format!("YAML: {}", e)))?
        }
        ConfigFormat::Toml => {
            toml::from_str(&content)
                .map_err(|e| ConfigError::ParseError(format!("TOML: {}", e)))?
        }
    };

    // Validate
    config.validate()?;

    info!(
        keys = %config.keys.len(),
        brightness = ?config.brightness,
        "Configuration loaded successfully"
    );

    Ok(config)
}

#[derive(Debug, Clone, serde::Deserialize)]
pub struct ProfileConfig {
    /// Optional profile name
    pub name: Option<String>,
    /// Target device serial (optional)
    pub device: Option<String>,
    /// Brightness level (0-100)
    pub brightness: Option<u8>,
    /// Key configurations
    #[serde(default)]
    pub keys: Vec<KeyConfig>,
}

impl ProfileConfig {
    pub fn validate(&self) -> Result<(), ConfigError> {
        // Validate brightness range
        if let Some(b) = self.brightness {
            if b > 100 {
                return Err(ConfigError::ValidationError(
                    format!("brightness {} out of range (0-100)", b)
                ));
            }
        }

        // Validate each key config
        for key in &self.keys {
            key.validate()?;
        }

        Ok(())
    }
}
