## Implementation

### Key Layout Grid Generator
```rust
impl HumanOutput {
    /// Generate ASCII art key layout grid
    fn render_key_layout(&self, rows: u8, cols: u8) -> String {
        let mut grid = String::new();

        // Calculate cell width (need room for 2-digit numbers)
        let cell_width = 2;

        // Top border
        grid.push_str("  ┌");
        for c in 0..cols {
            grid.push_str(&"─".repeat(cell_width));
            if c < cols - 1 { grid.push('┬'); }
        }
        grid.push_str("┐\n");

        // Rows with content
        for r in 0..rows {
            grid.push_str("  │");
            for c in 0..cols {
                let key_num = r * cols + c;
                grid.push_str(&format!("{:>2}", key_num));
                if c < cols - 1 { grid.push('│'); }
            }
            grid.push_str("│\n");

            // Row separator (except after last row)
            if r < rows - 1 {
                grid.push_str("  ├");
                for c in 0..cols {
                    grid.push_str(&"─".repeat(cell_width));
                    if c < cols - 1 { grid.push('┼'); }
                }
                grid.push_str("┤\n");
            }
        }

        // Bottom border
        grid.push_str("  └");
        for c in 0..cols {
            grid.push_str(&"─".repeat(cell_width));
            if c < cols - 1 { grid.push('┴'); }
        }
        grid.push_str("┘\n");

        grid
    }
}
