```rust
// src/commands/set_key.rs
use std::path::Path;
use crate::device::{DeviceOperations, DeviceInfo};
use crate::error::{Result, SdError};
use crate::output::{Output, DryRunResponse, SetKeyDetails, ImageSource};
use tracing::{debug, info, instrument};

#[derive(Debug)]
pub struct SetKeyOptions {
    pub key: u8,
    pub image_path: PathBuf,
    pub dry_run: bool,
}

#[instrument(skip(device, output))]
pub async fn cmd_set_key(
    device: &mut dyn DeviceOperations,
    options: SetKeyOptions,
    output: &dyn Output,
) -> Result<()> {
    let device_info = device.info();

    // Validate key index
    if options.key >= device_info.key_count {
        return Err(SdError::InvalidKey(options.key, device_info.key_count));
    }

    // Analyze the source image
    let source_info = analyze_image(&options.image_path)?;

    // Calculate processing requirements
    let target_dims = device_info.key_dimensions();
    let resize_needed = source_info.width != target_dims.0 || 
                        source_info.height != target_dims.1;

    if options.dry_run {
        let details = SetKeyDetails {
            key: options.key,
            source: source_info,
            processing: ProcessingInfo {
                resize_needed,
                target_dimensions: target_dims,
                estimated_time_ms: estimate_processing_time(&source_info, resize_needed),
            },
        };

        let response = DryRunResponse::success(
            "set_key_image",
            details,
            device_context(device_info),
        );

        // Add warning if resize needed
        let response = if resize_needed {
            response.with_warnings(vec![
                format!(
                    "Image dimensions ({}x{}) will be resized to {}x{}",
                    source_info.width, source_info.height,
                    target_dims.0, target_dims.1
                )
            ])
        } else {
            response
        };

        return output.dry_run(&response);
    }

    // Actually apply the image
    info!(key = options.key, path = %options.image_path.display(), "Setting key image");
    device.set_key_image(options.key, &options.image_path).await?;

    output.set_key_success(options.key, &options.image_path)
}

/// Analyze an image file without loading full pixel data
fn analyze_image(path: &Path) -> Result<ImageSource> {
    use image::io::Reader as ImageReader;

    // Check file exists
    if !path.exists() {
        return Err(SdError::ImageNotFound(path.display().to_string()));
    }

    // Check file is readable
    let metadata = std::fs::metadata(path)
        .map_err(|e| SdError::IoError(e))?;

    if !metadata.is_file() {
        return Err(SdError::ImageNotFound(format!(
            "{} is not a file", path.display()
        )));
    }

    // Get format from extension
    let format = path.extension()
        .and_then(|e| e.to_str())
        .map(|e| e.to_lowercase())
        .unwrap_or_default();

    // Read image dimensions without decoding full image
    let reader = ImageReader::open(path)
        .map_err(|e| SdError::ImageFormat(format!("Cannot open: {}", e)))?
        .with_guessed_format()
        .map_err(|e| SdError::ImageFormat(format!("Unknown format: {}", e)))?;

    let dimensions = reader.into_dimensions()
        .map_err(|e| SdError::ImageFormat(format!("Cannot read dimensions: {}", e)))?;

    Ok(ImageSource {
        path: path.to_path_buf(),
        exists: true,
        readable: true,
        format: Some(format),
        dimensions: Some((dimensions.0, dimensions.1)),
        size_bytes: Some(metadata.len()),
    })
}

fn estimate_processing_time(source: &ImageSource, resize_needed: bool) -> Option<u32> {
    if !resize_needed {
        return Some(5); // Just format conversion
    }

    // Rough estimate based on pixel count
    if let Some((w, h)) = source.dimensions {
        let pixels = w * h;
        // Assume ~1ms per 10,000 pixels for resize
        Some(((pixels as f64 / 10000.0) + 10.0) as u32)
    } else {
        None
    }
}

fn device_context(info: &DeviceInfo) -> DeviceContext {
    DeviceContext {
        model: format!("{:?}", info.model),
        serial: Some(info.serial.clone()),
        connected: true,
        key_count: info.key_count,
        key_dimensions: info.key_dimensions(),
    }
}
