## Implementation

```rust
// src/config/selector.rs
use std::str::FromStr;
use crate::error::{Result, SdError};
use crate::device::DeviceInfo;

/// Selector for targeting one or more keys in configuration
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum KeySelector {
    /// Single key by index: "0", "15"
    Single(u8),

    /// Inclusive range: "8-15"
    Range { start: u8, end: u8 },

    /// All keys in a row: "row-0", "row-3"
    Row(u8),

    /// All keys in a column: "col-0", "col-4"
    Column(u8),

    /// All keys not matched by other selectors
    Default,
}

impl KeySelector {
    /// Parse selector from string
    pub fn parse(s: &str) -> Result<Self> {
        let s = s.trim();

        if s == "default" {
            return Ok(KeySelector::Default);
        }

        if let Some(row) = s.strip_prefix("row-") {
            let row_num = row.parse::<u8>()
                .map_err(|_| SdError::ConfigParse(format!("Invalid row number: {}", row)))?;
            return Ok(KeySelector::Row(row_num));
        }

        if let Some(col) = s.strip_prefix("col-") {
            let col_num = col.parse::<u8>()
                .map_err(|_| SdError::ConfigParse(format!("Invalid column number: {}", col)))?;
            return Ok(KeySelector::Column(col_num));
        }

        if let Some(dash_pos) = s.find('-') {
            // Could be negative number or range
            if dash_pos > 0 {
                let start = s[..dash_pos].parse::<u8>()
                    .map_err(|_| SdError::ConfigParse(format!("Invalid range start: {}", &s[..dash_pos])))?;
                let end = s[dash_pos + 1..].parse::<u8>()
                    .map_err(|_| SdError::ConfigParse(format!("Invalid range end: {}", &s[dash_pos + 1..])))?;

                if start > end {
                    return Err(SdError::ConfigParse(
                        format!("Range start ({}) must be <= end ({})", start, end)
                    ));
                }

                return Ok(KeySelector::Range { start, end });
            }
        }

        // Try single key index
        let index = s.parse::<u8>()
            .map_err(|_| SdError::ConfigParse(format!("Invalid key selector: '{}'", s)))?;

        Ok(KeySelector::Single(index))
    }

    /// Resolve selector to concrete key indices for a device
    pub fn resolve(&self, device: &DeviceInfo) -> Result<Vec<u8>> {
        match self {
            KeySelector::Single(idx) => {
                if *idx >= device.key_count {
                    return Err(SdError::InvalidKey(*idx, device.key_count));
                }
                Ok(vec![*idx])
            }

            KeySelector::Range { start, end } => {
                if *end >= device.key_count {
                    return Err(SdError::InvalidKey(*end, device.key_count));
                }
                Ok((*start..=*end).collect())
            }

            KeySelector::Row(row) => {
                if *row >= device.key_rows {
                    return Err(SdError::ConfigInvalid(
                        format!("Row {} out of range (device has {} rows)", row, device.key_rows)
                    ));
                }
                let start = *row * device.key_cols;
                let end = start + device.key_cols;
                Ok((start..end).collect())
            }

            KeySelector::Column(col) => {
                if *col >= device.key_cols {
                    return Err(SdError::ConfigInvalid(
                        format!("Column {} out of range (device has {} columns)", col, device.key_cols)
                    ));
                }
                let indices: Vec<u8> = (0..device.key_rows)
                    .map(|row| row * device.key_cols + col)
                    .collect();
                Ok(indices)
            }

            KeySelector::Default => {
                // Return empty - handled specially during config resolution
                Ok(vec![])
            }
        }
    }

    /// Priority for resolution (lower = higher priority)
    pub fn priority(&self) -> u8 {
        match self {
            KeySelector::Single(_) => 0,
            KeySelector::Range { .. } => 1,
            KeySelector::Row(_) | KeySelector::Column(_) => 2,
            KeySelector::Default => 255,
        }
    }
}

impl FromStr for KeySelector {
    type Err = SdError;

    fn from_str(s: &str) -> Result<Self> {
        Self::parse(s)
    }
}

/// Custom deserializer for YAML map keys
impl<'de> serde::Deserialize<'de> for KeySelector {
    fn deserialize<D>(deserializer: D) -> std::result::Result<Self, D::Error>
    where
        D: serde::Deserializer<'de>,
    {
        let s = String::deserialize(deserializer)?;
        KeySelector::parse(&s).map_err(serde::de::Error::custom)
    }
}

impl serde::Serialize for KeySelector {
    fn serialize<S>(&self, serializer: S) -> std::result::Result<S::Ok, S::Error>
    where
        S: serde::Serializer,
    {
        let s = match self {
            KeySelector::Single(idx) => idx.to_string(),
            KeySelector::Range { start, end } => format!("{}-{}", start, end),
            KeySelector::Row(row) => format!("row-{}", row),
            KeySelector::Column(col) => format!("col-{}", col),
            KeySelector::Default => "default".to_string(),
        };
        serializer.serialize_str(&s)
    }
}
