Create the foundational web server infrastructure using axum for the Stream Deck web dashboard.

## Implementation
```rust
// src/server/mod.rs
pub mod api;
pub mod state;

use axum::{Router, routing::get, Extension};
use std::net::SocketAddr;
use std::sync::Arc;
use tokio::sync::RwLock;
use tower_http::cors::{CorsLayer, Any};
use tower_http::services::ServeDir;
use tracing::{debug, info, warn, error, instrument};

use crate::device::Device;

pub use state::AppState;

/// Server configuration
#[derive(Debug, Clone)]
pub struct ServerConfig {
    pub port: u16,
    pub host: String,
    pub auto_open: bool,
    pub static_dir: Option<std::path::PathBuf>,
}

impl Default for ServerConfig {
    fn default() -> Self {
        Self {
            port: 8420,
            host: "127.0.0.1".to_string(),
            auto_open: true,
            static_dir: None,
        }
    }
}

/// Create the main application router
#[instrument(skip(state))]
pub fn create_router(state: AppState, config: &ServerConfig) -> Router {
    info!("Creating API router");

    let api_routes = Router::new()
        .route("/device", get(api::get_device_info))
        .route("/brightness", get(api::get_brightness).put(api::set_brightness))
        .route("/keys", get(api::get_keys))
        .route("/keys/:id", 
            axum::routing::put(api::set_key)
                .delete(api::clear_key))
        .route("/keys/:id/color", axum::routing::put(api::set_key_color))
        .route("/health", get(api::health_check));

    let mut router = Router::new()
        .nest("/api", api_routes)
        .layer(CorsLayer::new()
            .allow_origin(Any)
            .allow_methods(Any)
            .allow_headers(Any))
        .with_state(state);

    // Serve static files (frontend)
    if let Some(ref static_dir) = config.static_dir {
        debug!(dir = %static_dir.display(), "Serving static files");
        router = router.nest_service("/", ServeDir::new(static_dir));
    } else {
        // In release builds, serve embedded assets
        #[cfg(not(debug_assertions))]
        {
            use crate::server::embedded::EmbeddedAssets;
            router = router.fallback_service(EmbeddedAssets);
        }

        #[cfg(debug_assertions)]
        {
            // In debug, serve from default static directory
            let default_static = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"))
                .join("static");
            if default_static.exists() {
                debug!(dir = %default_static.display(), "Serving static files from default location");
                router = router.nest_service("/", ServeDir::new(default_static));
            }
        }
    }

    router
}

/// Start the web server
#[instrument(skip(device))]
pub async fn start_server(
    device: Device,
    config: ServerConfig,
) -> Result<(), ServerError> {
    let addr: SocketAddr = format!("{}:{}", config.host, config.port)
        .parse()
        .map_err(|e| ServerError::InvalidAddress(format!("{}", e)))?;

    let state = AppState::new(device);
    let router = create_router(state, &config);

    info!(
        host = %config.host,
        port = %config.port,
        "Starting web server"
    );

    // Auto-open browser
    if config.auto_open {
        let url = format!("http://{}:{}", config.host, config.port);
        info!(url = %url, "Opening browser");

        if let Err(e) = open_browser(&url) {
            warn!(error = %e, "Failed to open browser automatically");
        }
    }

    println!("Stream Deck web interface running at http://{}:{}", config.host, config.port);
    println!("Press Ctrl+C to stop");

    let listener = tokio::net::TcpListener::bind(addr).await
        .map_err(|e| ServerError::BindFailed(e))?;

    axum::serve(listener, router)
        .await
        .map_err(|e| ServerError::ServerFailed(e))?;

    Ok(())
}

/// Open URL in default browser
fn open_browser(url: &str) -> Result<(), std::io::Error> {
    #[cfg(target_os = "macos")]
    {
        std::process::Command::new("open").arg(url).spawn()?;
    }

    #[cfg(target_os = "linux")]
    {
        std::process::Command::new("xdg-open").arg(url).spawn()?;
    }

    #[cfg(target_os = "windows")]
    {
        std::process::Command::new("cmd")
            .args(["/C", "start", url])
            .spawn()?;
    }

    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum ServerError {
    #[error("Invalid address: {0}")]
    InvalidAddress(String),

    #[error("Failed to bind to address: {0}")]
    BindFailed(std::io::Error),

    #[error("Server error: {0}")]
    ServerFailed(std::io::Error),
}
